CREATE OR REPLACE FUNCTION fpa_gos_sum_pending (ai_year bigint , ai_month bigint , as_memno char) RETURNS bigint AS $body$
DECLARE

  ldc_val bigint;

BEGIN
    select sum(money_amount) into STRICT ldc_val
    from sc_kep_t_monthly_receive_det
    where receive_year = ai_year
    and receive_month = ai_month
    and membership_no = as_memno;

  return coalesce(ldc_val,0);

exception when others then CALL spa_dberror('fpa_gos_sum_pending');
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
